"""Control Gauntlet

Short-circuit evaluation, De Morgan's law, break, and continue. Fix demorgan.cpp and break_continue.cpp; short_circuit.cpp is an exploration demo.
"""
import os, shutil, subprocess, sys, tempfile, zipfile, textwrap
import hashlib as _hl, hmac as _hm

SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
REPO_ZIP   = os.path.join(SCRIPT_DIR, "repo.zip")

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000
_BLOB      = "6148e3d52fc041d42fedec3cba81598fae5bd94cb9105f099865b0a4bc9c5daeab29e312834d60f3c50765da6258"

def _decrypt(key_str):
    key  = _hl.pbkdf2_hmac("sha256", key_str.encode(), _SALT, _KDF_ITERS)
    blob = bytes.fromhex(_BLOB)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    ks, i, stream = b"", 0, b""
    while len(stream) < len(ct):
        stream += _hl.sha256(key + i.to_bytes(4, "little")).digest()
        i += 1
    return bytes(a ^ b for a, b in zip(ct, stream)).decode()

_LINE_WIDTH = 70

def _banner(title):
    print("=" * _LINE_WIDTH)
    pad = (_LINE_WIDTH - len(title) - 2) // 2
    print(" " * pad + " " + title + " " * pad)
    print("=" * _LINE_WIDTH)

def _hr():
    print("-" * _LINE_WIDTH)

def _show_passphrase(passphrase):
    print()
    _hr()
    print(f"  Passphrase: {passphrase}")
    _hr()
    print()

def die(msg):
    print(f"error: {msg}", file=sys.stderr)
    sys.exit(1)

def _compile_run(src, name, repo_dir):
    binary = os.path.join(repo_dir, name)
    r = subprocess.run(
        ["g++", "-std=c++17", "-o", binary, os.path.join(repo_dir, src)],
        capture_output=True, text=True,
    )
    if r.returncode != 0:
        return None, r.stderr
    try:
        run = subprocess.run([binary], capture_output=True, text=True, timeout=10)
    except subprocess.TimeoutExpired:
        return None, "timeout"
    return run.stdout.strip(), None

def _validate(repo_dir):
    out_dm, err_dm = _compile_run("demorgan.cpp", "demorgan", repo_dir)
    if out_dm is None:
        return False, "compile-error", "demorgan.cpp", err_dm
    out_bc, err_bc = _compile_run("break_continue.cpp", "break_continue", repo_dir)
    if out_bc is None:
        return False, "compile-error", "break_continue.cpp", err_bc
    key_str = f"{out_dm}|{out_bc}"
    return True, key_str, None, None

def _all_binaries_exist(repo_dir):
    return (os.path.isfile(os.path.join(repo_dir, "demorgan")) and
            os.path.isfile(os.path.join(repo_dir, "break_continue")))

def main():
    if not os.path.isfile(REPO_ZIP):
        die("repo.zip not found.")

    work_dir = tempfile.mkdtemp(prefix="control-gauntlet-")
    with zipfile.ZipFile(REPO_ZIP, "r") as zf:
        zf.extractall(work_dir)
    entries = os.listdir(work_dir)
    if len(entries) != 1:
        shutil.rmtree(work_dir, ignore_errors=True)
        die("unexpected zip structure")
    repo_dir = os.path.join(work_dir, entries[0])

    banner_text = """
      ============================================================
       Control Gauntlet
      ============================================================

       Three programs.  One to explore, two to fix.
       
         Step 1 -- run the demo (nothing to fix):
           g++ -std=c++17 -o short_circuit short_circuit.cpp && ./short_circuit
           Watch which function calls get skipped.
       
         Step 2 -- fix the bug in demorgan.cpp:
           The function keep() uses the wrong logical operator.
           Apply De Morgan's law and change one character.
           Expected output:  Kept: 5
       
         Step 3 -- fix the two bugs in break_continue.cpp:
           Loop 1 needs a break; to stop at the first match.
           Loop 2 needs a continue; to skip even numbers.
           Expected output:  First: 7 Sum: 25
       
         Step 4 -- compile both fixed programs:
           g++ -std=c++17 -o demorgan demorgan.cpp
           g++ -std=c++17 -o break_continue break_continue.cpp
       
         Then type 'exit'.  The launcher checks your work.
      ============================================================

    """
    rcfile = tempfile.NamedTemporaryFile(mode="w", suffix=".rc", delete=False)
    rcfile.write(
        f'PS1=\'\\u@control-gauntlet:\\W\\$ \'\n'
        f'cd "{repo_dir}"\n'
        "cat << \'BANNER\'\n" + banner_text + "\nBANNER\n"
    )
    rcfile.close()

    shell = os.environ.get("SHELL", "/bin/bash")

    try:
        while True:
            subprocess.run([shell, "--rcfile", rcfile.name])

            if not _all_binaries_exist(repo_dir):
                print()
                print("  Please compile both programs before exiting:")
                print("    g++ -std=c++17 -o demorgan demorgan.cpp")
                print("    g++ -std=c++17 -o break_continue break_continue.cpp")
                print()
                try:
                    again = input("  Try again? [y/n] ").strip().lower()
                except (EOFError, KeyboardInterrupt):
                    print()
                    break
                if again == "y":
                    continue
                break

            print()
            _banner("Control Gauntlet -- Checking Your Work")
            print()

            ok, key_str, which, detail = _validate(repo_dir)

            if ok:
                passphrase = _decrypt(key_str)
                if passphrase is not None:
                    _show_passphrase(passphrase)
                    break
                print("  Both programs compiled and ran, but the output was not correct.")
                print("  Check that each prints the expected values.")
            elif key_str == "compile-error":
                if detail == "timeout":
                    print(f"  {which} did not finish in time.")
                else:
                    print(f"  {which} did not compile.  Error:\n")
                    for line in detail.strip().splitlines():
                        print(f"    {line}")

            print()
            try:
                again = input("  Try again? [y/n] ").strip().lower()
            except (EOFError, KeyboardInterrupt):
                print()
                break
            if again == "y":
                print()
                continue
            break

    finally:
        try:
            os.remove(rcfile.name)
        except OSError:
            pass
        shutil.rmtree(work_dir, ignore_errors=True)


if __name__ == "__main__":
    main()
